static uint16_t compute_install_code_crc(const uint8_t *code, uint8_t length)
{
    /* CRC-CCITT (0xFFFF) as specified in Zigbee spec */
    uint16_t crc = 0xFFFF;

    for (uint8_t i = 0; i < length; i++) {
        crc ^= (uint16_t)code[i] << 8;
        for (uint8_t j = 0; j < 8; j++) {
            if (crc & 0x8000) {
                crc = (crc << 1) ^ 0x1021;
            } else {
                crc <<= 1;
            }
        }
    }

    return crc;
}

